331→                    initialFetchResolvedRef.current = true;
332→                    setIsInitialLoading(false);
333→                }
334→            }
335→        }, 400);
336→
337→        return () => {
338→            if (fetchDebounceRef.current) clearTimeout(fetchDebounceRef.current);
339→        };
