  1→import { useState, useEffect, useRef, useMemo } from 'react';
  2→import {
  3→    computeGalaxyForces,
  4→    computeGalaxySimilarityEdges,
  5→    computeSectorKey,
  6→    computeStarPullOffsets,
  7→    computeStarPullOffsetsFromEmbeddings,
  8→} from '../utils/cosmicPhysics';
  9→import { userHomeCoords } from '../utils/starUtils';
 10→
 11→const COOLING = 0.95;
 12→const DAMPING = 0.9;
 13→const BOUNDARY = 25000;
 14→const RENDER_EVERY = 3; // only push state to React every N frames
 15→const SETTLE_EPSILON = 0.35;
 16→const SETTLE_FRAMES = 8;
 17→
 18→export default function useCosmicGravity({
 19→    galaxies,
 20→    centroidTargets,
 21→    edges,
 22→    posts,
 23→    starPulls,
 24→    centroidByUser,
 25→    activeSectorKeys,
 26→    activePostIds,
 27→    sectorSize = 2000,
 28→}) {
 29→    const [galaxyPositions, setGalaxyPositions] = useState(new Map());
 30→    const [isSettled, setIsSettled] = useState(true);
 31→
 32→    const galPosRef = useRef(new Map());
 33→    const tempRef = useRef(1.0);
 34→    const rafRef = useRef(null);
 35→    const frameCountRef = useRef(0);
 36→    const steadyFrameRef = useRef(0);
 37→
 38→    const emptyMap = useMemo(() => new Map(), []);
 39→
 40→    const hasEmbeddingCentroids = centroidByUser instanceof Map && centroidByUser.size > 1;
 41→    const hasServerTargets = centroidTargets instanceof Map && centroidTargets.size > 0;
 42→    const hasServerEdges = Array.isArray(edges) && edges.length > 0;
 43→
 44→    const activePosts = useMemo(() => {
 45→        if (!Array.isArray(posts) || posts.length === 0) return [];
 46→
 47→        if (!(activeSectorKeys instanceof Set) || activeSectorKeys.size === 0) {
 48→            return posts;
 49→        }
 50→
 51→        const filtered = [];
 52→        for (const post of posts) {
 53→            const x = post?.display_x ?? post?.universe_x;
 54→            const y = post?.display_y ?? post?.universe_y;
 55→            const sectorKey = computeSectorKey(x, y, sectorSize);
 56→            if (sectorKey && activeSectorKeys.has(sectorKey)) {
 57→                filtered.push(post);
 58→            }
 59→        }
 60→        return filtered;
 61→    }, [posts, activeSectorKeys, sectorSize]);
 62→
 63→    const effectiveActivePostIds = useMemo(() => {
 64→        if (activePostIds instanceof Set && activePostIds.size > 0) return activePostIds;
 65→        const ids = new Set();
 66→        for (const post of activePosts) {
 67→            if (post?.id) ids.add(post.id);
 68→        }
 69→        return ids;
 70→    }, [activePostIds, activePosts]);
 71→
 72→    const activeUserIds = useMemo(() => {
 73→        const ids = new Set();
 74→        for (const post of activePosts) {
 75→            const userId = post?.users?.id ?? post?.user_id;
 76→            if (userId) ids.add(userId);
 77→        }
 78→
 79→        // Keep fallback behavior stable when sector data is sparse.
 80→        if (ids.size === 0 && Array.isArray(galaxies)) {
 81→            for (const galaxy of galaxies) {
 82→                if (galaxy?.userId) ids.add(galaxy.userId);
 83→            }
 84→        }
 85→        return ids;
 86→    }, [activePosts, galaxies]);
 87→
 88→    const localEdges = useMemo(() => {
 89→        if (!hasEmbeddingCentroids || activeUserIds.size < 2) return [];
 90→        return computeGalaxySimilarityEdges(centroidByUser, activeUserIds, 0.3, 800);
 91→    }, [hasEmbeddingCentroids, centroidByUser, activeUserIds]);
 92→
 93→    const effectiveEdges = hasEmbeddingCentroids ? localEdges : (Array.isArray(edges) ? edges : []);
 94→    const effectiveTargets = hasEmbeddingCentroids
 95→        ? emptyMap
 96→        : (centroidTargets instanceof Map ? centroidTargets : emptyMap);
 97→
 98→    const hasGravityData = hasEmbeddingCentroids
 99→        ? effectiveEdges.length > 0
100→        : (hasServerTargets || hasServerEdges);
101→
102→    // Merge galaxies into existing positions (never reset settled ones).
103→    useEffect(() => {
104→        if (!Array.isArray(galaxies) || galaxies.length === 0) return;
105→
106→        const current = galPosRef.current;
107→        const merged = new Map(current);
108→        let hasNew = false;
109→        let hasRemoved = false;
110→
111→        for (const galaxy of galaxies) {
112→            if (!merged.has(galaxy.userId)) {
113→                const hash = userHomeCoords(galaxy.userId);
114→                merged.set(galaxy.userId, { x: hash.x, y: hash.y });
115→                hasNew = true;
116→            }
117→        }
118→
119→        const visibleIds = new Set(galaxies.map((g) => g.userId));
120→        for (const id of current.keys()) {
121→            if (!visibleIds.has(id)) {
122→                merged.delete(id);
123→                hasRemoved = true;
124→            }
125→        }
126→
127→        if (hasNew || hasRemoved || current.size === 0) {
128→            galPosRef.current = merged;
129→            setGalaxyPositions(new Map(merged));
130→        }
131→
132→        if (hasGravityData && (hasNew || hasRemoved || isSettled)) {
133→            tempRef.current = Math.max(tempRef.current, 0.85);
134→            steadyFrameRef.current = 0;
135→            setIsSettled(false);
136→        }
137→    }, [galaxies, hasGravityData, isSettled]);
138→
139→    // Warm restart when gravity inputs change (new embeddings, sectors, or targets).
140→    useEffect(() => {
141→        if (!hasGravityData || galPosRef.current.size === 0) return;
142→        tempRef.current = Math.max(tempRef.current, 0.75);
143→        steadyFrameRef.current = 0;
144→        setIsSettled(false);
145→    }, [hasGravityData, effectiveTargets, effectiveEdges, activeSectorKeys]);
146→
147→    // Galaxy animation loop (Gravity A).
148→    useEffect(() => {
149→        if (isSettled || !hasGravityData) return;
150→
151→        let active = true;
152→        frameCountRef.current = 0;
153→        steadyFrameRef.current = 0;
154→
155→        const tick = () => {
156→            if (!active) return;
157→
158→            const activeIds = hasEmbeddingCentroids
159→                ? new Set(Array.from(activeUserIds).filter((id) => galPosRef.current.has(id)))
160→                : new Set(galPosRef.current.keys());
161→
162→            if (activeIds.size === 0) {
163→                setIsSettled(true);
164→                return;
165→            }
166→
167→            const forces = computeGalaxyForces(galPosRef.current, effectiveTargets, effectiveEdges, {
168→                activeIds,
169→            });
170→
171→            const newPos = new Map();
172→            let maxDisp = 0;
173→
174→            for (const [id, pos] of galPosRef.current.entries()) {
175→                const force = forces.get(id);
176→                if (!force) {
177→                    newPos.set(id, pos);
178→                    continue;
179→                }
180→
181→                let nx = pos.x + force.fx * tempRef.current * DAMPING;
182→                let ny = pos.y + force.fy * tempRef.current * DAMPING;
183→
184→                nx = Math.max(-BOUNDARY, Math.min(BOUNDARY, nx));
185→                ny = Math.max(-BOUNDARY, Math.min(BOUNDARY, ny));
186→
187→                const dx = nx - pos.x;
188→                const dy = ny - pos.y;
189→                const disp = Math.sqrt(dx * dx + dy * dy);
190→                if (disp > maxDisp) maxDisp = disp;
191→
192→                newPos.set(id, { x: nx, y: ny });
193→            }
194→
195→            galPosRef.current = newPos;
196→            tempRef.current *= COOLING;
197→            frameCountRef.current++;
198→
199→            if (maxDisp < SETTLE_EPSILON) {
200→                steadyFrameRef.current++;
201→            } else {
202→                steadyFrameRef.current = 0;
203→            }
204→
205→            if (steadyFrameRef.current >= SETTLE_FRAMES || tempRef.current < 0.006) {
206→                setGalaxyPositions(new Map(newPos));
207→                setIsSettled(true);
208→                return;
209→            }
210→
211→            if (frameCountRef.current % RENDER_EVERY === 0) {
212→                setGalaxyPositions(new Map(newPos));
213→            }
214→
215→            rafRef.current = requestAnimationFrame(tick);
216→        };
217→
218→        rafRef.current = requestAnimationFrame(tick);
219→
220→        return () => {
221→            active = false;
222→            if (rafRef.current) cancelAnimationFrame(rafRef.current);
223→        };
224→    }, [
225→        isSettled,
226→        hasGravityData,
227→        hasEmbeddingCentroids,
228→        activeUserIds,
229→        effectiveTargets,
230→        effectiveEdges,
231→    ]);
232→
233→    // Star pull offsets (Gravity B).
234→    const starPullOffsets = useMemo(() => {
235→        if (!Array.isArray(posts) || posts.length === 0) return new Map();
236→
237→        if (hasEmbeddingCentroids) {
238→            const positionsSource = galaxyPositions.size > 0 ? galaxyPositions : galPosRef.current;
239→            return computeStarPullOffsetsFromEmbeddings({
240→                posts: activePosts,
241→                galaxyCentroids: centroidByUser,
242→                galaxyPositions: positionsSource,
243→                activePostIds: effectiveActivePostIds,
244→                activeGalaxyIds: activeUserIds,
245→                minSimilarity: 0.4,
246→                pullStrength: 120,
247→                maxOffset: 80,
248→                maxGalaxyLinks: 6,
249→            });
250→        }
251→
252→        if (!Array.isArray(starPulls) || starPulls.length === 0) return new Map();
253→        const galaxyTargets = centroidTargets instanceof Map ? centroidTargets : emptyMap;
254→        if (galaxyTargets.size === 0) return new Map();
255→
256→        const starBases = new Map();
257→        for (const post of posts) {
258→            const x = post?.universe_x ?? post?.display_x;
259→            const y = post?.universe_y ?? post?.display_y;
260→            if (x != null && y != null && post?.id) {
261→                starBases.set(post.id, { x, y });
262→            }
263→        }
264→
265→        return computeStarPullOffsets(starPulls, galaxyTargets, starBases);
266→    }, [
267→        posts,
268→        hasEmbeddingCentroids,
269→        galaxyPositions,
270→        activePosts,
271→        centroidByUser,
272→        effectiveActivePostIds,
273→        activeUserIds,
274→        starPulls,
275→        centroidTargets,
276→        emptyMap,
277→    ]);
278→
279→    return {
280→        galaxyPositions,
281→        starPullOffsets,
282→        isSettled,
283→        galaxyEdges: effectiveEdges,
284→        hasEmbeddingGravity: hasEmbeddingCentroids,
285→    };
286→}
